import React, { useEffect } from "react";
import { useAppDispatch, useAppSelector } from "../../app/hooks";
import { loadPoints, selectResultTable } from "./ResultTableSlice";
import { selectAuth } from "../auth/authSlice";
import styles from "./ResultTable.module.css";
import { PointRow } from "./ResultTableAPI";

export function ResultTable() {
  const dispatch = useAppDispatch();
  const { points, loading, error } = useAppSelector(selectResultTable);
  const { isLogin } = useAppSelector(selectAuth);

  useEffect(() => {
    if (isLogin) {
      dispatch(loadPoints());
    }
  }, [isLogin, dispatch]);

  if (loading) {
    return <div className={styles.loading}>Загрузка результатов</div>;
  }

  if (error) {
    return <div className={styles.error}>Ошибка: {error}</div>;
  }

  return (
    <div className={styles.tableContainer}>
      <h2 className={styles.tableTitle}>Результаты проверок</h2>

      <div className={styles.responsiveTable}>
        <table className={styles.table}>
          <thead>
            <tr>
              <th>X</th>
              <th>Y</th>
              <th>R</th>
              <th>Попадание</th>
              <th>Время работы (нс)</th>
              <th>Дата и время</th>
            </tr>
          </thead>
          <tbody>
            {points.map((point: PointRow, index: number) => (
              <tr
                key={index} >
                <td>{point.x}</td>
                <td>{point.y.toFixed(5)}</td>
                <td>{point.r}</td>
                <td>{point.hit ? "Да" : "Нет"}</td>
                <td>{point.execTime}</td>
                <td>{point.dateFormatted}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className={styles.mobileView}>
        {points.map((point: PointRow, index: number) => (
          <div
            key={index}
            className={`${styles.mobileRow}`}
          >
            <strong>
              ({point.x}, {point.y.toFixed(3)})
            </strong>{" "}
            R: {point.r}
            <br />
            <strong>Попадание:</strong> {point.hit ? "Да" : "Нет"}
            <br />
            <strong>Время:</strong> {point.execTime} нс
            <br />
            <strong>Дата:</strong> {point.dateFormatted}
          </div>
        ))}
      </div>
    </div>
  );
}