import React from "react";
import { Routes, Route, Navigate } from "react-router-dom";
import { useAppSelector } from "./app/hooks";
import { selectAuth } from "./features/auth/authSlice";
import { LoginPage } from "./features/loginPage/LoginPage";
import { MainPage } from "./features/mainPage/MainPage";
import { RegisterPage } from "./features/registerPage/RegisterPage";
import styles from "./App.module.css";

export default function App() {
  const { isLogin, loading } = useAppSelector(selectAuth);

  if (loading) {
    return (
      <div className={styles.loadingContainer}>
        <div className={styles.loadingText}>Загрузка</div>
      </div>
    );
  }

  return (
    <div className={styles.appContainer}>
      <Routes>
        <Route
          path="/login"
          // element={<MainPage />}
          element={
            isLogin ? <Navigate to="/main" replace /> : <LoginPage />
          }
        />

        <Route
          path="/register"
          element={
            isLogin ? <Navigate to="/main" replace /> : <RegisterPage />
          }
        />

        <Route
          path="/main"
          element={
            isLogin ? <MainPage /> : <Navigate to="/login" replace />
          }
        />

        <Route
          path="/*"
          element={
            <Navigate to={isLogin ? "/main" : "/login"} replace />
          }
        />
      </Routes>
    </div>
  );
}